<script setup lang="ts">
/* eslint-disable vue/html-closing-bracket-newline, vue/html-indent, vue/html-self-closing -- Prettier owns Vue template formatting. */
import type { SceneMergerLocalizer } from "../../../../state/scene-merger";
import { useSceneMergerStore } from "../../../../state/scene-merger";
import type { SnapMode } from "../../../../types/scene-merger";

defineProps<{ readonly t: SceneMergerLocalizer }>();
const emit = defineEmits<{ fit: []; reset: []; zoom: [factor: number] }>();
const store = useSceneMergerStore();

function changeSnap(event: Event): void {
  store.setSnap((event.currentTarget as HTMLSelectElement).value as SnapMode);
}

function changeInterval(event: Event): void {
  store.setSnap(store.snap.mode, Number((event.currentTarget as HTMLInputElement).value));
}
</script>

<template>
  <div class="tw:flex tw:flex-wrap tw:items-end tw:justify-between tw:gap-2">
    <div class="tw:flex tw:flex-wrap tw:items-end tw:gap-2">
      <fieldset class="dui-fieldset tw:p-0">
        <legend class="dui-fieldset-legend tw:py-0 tw:text-[0.68rem]">
          {{ t("FVTT_SCENE_MERGER.Layout.SnapMode") }}
        </legend>
        <select
          class="dui-select dui-select-sm"
          :value="store.snap.mode"
          :disabled="!store.setupEditable"
          @change="changeSnap"
        >
          <option value="none">{{ t("FVTT_SCENE_MERGER.Layout.Snap.none") }}</option>
          <option value="pixel">{{ t("FVTT_SCENE_MERGER.Layout.Snap.pixel") }}</option>
          <option value="grid">{{ t("FVTT_SCENE_MERGER.Layout.Snap.grid") }}</option>
          <option value="edge">{{ t("FVTT_SCENE_MERGER.Layout.Snap.edge") }}</option>
        </select>
      </fieldset>
      <fieldset v-if="store.snap.mode === 'pixel'" class="dui-fieldset tw:w-24 tw:p-0">
        <legend class="dui-fieldset-legend tw:py-0 tw:text-[0.68rem]">
          {{ t("FVTT_SCENE_MERGER.Layout.Interval") }}
        </legend>
        <input
          class="dui-input dui-input-sm tw:w-full"
          type="number"
          min="1"
          step="1"
          :value="store.snap.pixelInterval"
          :disabled="!store.setupEditable"
          @change="changeInterval"
        />
      </fieldset>
      <span
        v-if="store.snap.mode === 'grid'"
        class="dui-badge dui-badge-outline dui-badge-sm tw:mb-1.5"
      >
        {{ t("FVTT_SCENE_MERGER.Layout.GridSize", { size: store.snap.gridSize }) }}
      </span>
    </div>

    <div class="tw:flex tw:items-center tw:gap-1">
      <button
        class="dui-btn dui-btn-sm dui-btn-square"
        type="button"
        :disabled="!store.setupEditable"
        :aria-label="t('FVTT_SCENE_MERGER.Layout.ZoomOut')"
        @click="emit('zoom', 0.8)"
      >
        −
      </button>
      <span class="dui-badge dui-badge-ghost tw:min-w-16 tw:justify-center"
        >{{ Math.round(store.view.zoom * 100) }}%</span
      >
      <button
        class="dui-btn dui-btn-sm dui-btn-square"
        type="button"
        :disabled="!store.setupEditable"
        :aria-label="t('FVTT_SCENE_MERGER.Layout.ZoomIn')"
        @click="emit('zoom', 1.25)"
      >
        +
      </button>
      <button
        class="dui-btn dui-btn-sm"
        type="button"
        :disabled="!store.setupEditable"
        @click="emit('fit')"
      >
        {{ t("FVTT_SCENE_MERGER.Layout.ZoomFit") }}
      </button>
      <button
        class="dui-btn dui-btn-ghost dui-btn-sm"
        type="button"
        :disabled="!store.setupEditable"
        @click="emit('reset')"
      >
        {{ t("FVTT_SCENE_MERGER.Layout.ResetView") }}
      </button>
    </div>
  </div>
</template>
