import type {
  CoreDocumentType,
  SourceDocumentIdentity,
  SourceDocumentKey,
} from "../../../types/scene-merger";

export function sourceDocumentKey(identity: SourceDocumentIdentity): SourceDocumentKey {
  return JSON.stringify([
    identity.sceneId,
    identity.documentType,
    ...(identity.parentIds ?? []),
    identity.documentId,
  ]) as SourceDocumentKey;
}

export function createSourceDocumentKey(
  sceneId: string,
  documentType: CoreDocumentType,
  documentId: string,
  parentIds: readonly string[] = [],
): SourceDocumentKey {
  return sourceDocumentKey({ documentId, documentType, parentIds, sceneId });
}
