import type { Point, Rectangle, ScenePlacement, SnapSettings } from "../../../types/scene-merger";

function snapNumber(value: number, interval: number): number {
  const snapped = interval > 0 ? Math.round(value / interval) * interval : value;
  return Object.is(snapped, -0) ? 0 : snapped;
}

function closestCandidate(value: number, candidates: readonly number[], threshold: number): number {
  let closest = value;
  let distance = threshold + Number.EPSILON;

  for (const candidate of candidates) {
    const candidateDistance = Math.abs(candidate - value);

    if (candidateDistance < distance) {
      closest = candidate;
      distance = candidateDistance;
    }
  }

  return distance <= threshold ? closest : value;
}

function edgeCandidates(
  rectangle: Rectangle,
  others: readonly Rectangle[],
): { readonly x: readonly number[]; readonly y: readonly number[] } {
  const x: number[] = [];
  const y: number[] = [];

  for (const other of others) {
    x.push(
      other.x,
      other.x + other.width,
      other.x - rectangle.width,
      other.x + other.width - rectangle.width,
    );
    y.push(
      other.y,
      other.y + other.height,
      other.y - rectangle.height,
      other.y + other.height - rectangle.height,
    );
  }

  return { x, y };
}

export function snapPosition(
  rectangle: Rectangle,
  settings: SnapSettings,
  others: readonly Rectangle[] = [],
): Point {
  if (settings.mode === "pixel") {
    return {
      x: snapNumber(rectangle.x, settings.pixelInterval),
      y: snapNumber(rectangle.y, settings.pixelInterval),
    };
  }

  if (settings.mode === "grid") {
    return {
      x: snapNumber(rectangle.x, settings.gridSize),
      y: snapNumber(rectangle.y, settings.gridSize),
    };
  }

  if (settings.mode === "edge") {
    const candidates = edgeCandidates(rectangle, others);

    return {
      x: closestCandidate(rectangle.x, candidates.x, settings.edgeThreshold),
      y: closestCandidate(rectangle.y, candidates.y, settings.edgeThreshold),
    };
  }

  return { x: rectangle.x, y: rectangle.y };
}

export function snapPlacement(
  placement: ScenePlacement,
  settings: SnapSettings,
  others: readonly ScenePlacement[],
): ScenePlacement {
  return { ...placement, ...snapPosition(placement, settings, others) };
}
