<script setup lang="ts">
/* eslint-disable vue/html-self-closing -- Prettier owns Vue template formatting. */
import { CORE_CONTENT_CAPABILITIES, type ContentCategory } from "../../../../types/scene-merger";
import type { SceneMergerLocalizer } from "../../../../state/scene-merger";
import { useSceneMergerStore } from "../../../../state/scene-merger";

defineProps<{ readonly t: SceneMergerLocalizer }>();
const store = useSceneMergerStore();

const categories: readonly ContentCategory[] = [
  "backgrounds",
  "tiles",
  "walls",
  "lights",
  "sounds",
  "drawings",
  "notes",
  "regions",
  "tokens",
  "templates",
];

function toggleContent(category: ContentCategory, event: Event): void {
  store.setContent(category, (event.currentTarget as HTMLInputElement).checked);
}

function textDestination(event: Event): void {
  store.setDestination("name", (event.currentTarget as HTMLInputElement).value.trim());
}

function folderDestination(event: Event): void {
  store.setDestination("folderId", (event.currentTarget as HTMLSelectElement).value || null);
}

function booleanDestination(
  key: "activateAfterMerge" | "lockBackgroundTiles" | "navigation" | "openAfterMerge",
  event: Event,
): void {
  store.setDestination(key, (event.currentTarget as HTMLInputElement).checked);
}
</script>

<template>
  <section class="dui-card dui-card-border tw:bg-base-200">
    <div class="dui-card-body tw:gap-4 tw:p-3">
      <div>
        <h2 class="dui-card-title tw:text-base">{{ t("FVTT_SCENE_MERGER.Options.Title") }}</h2>
        <p class="tw:m-0 tw:text-xs tw:opacity-65">{{ t("FVTT_SCENE_MERGER.Options.Help") }}</p>
      </div>

      <div class="tw:grid tw:gap-4 tw:lg:grid-cols-2">
        <fieldset class="dui-fieldset tw:min-w-0 tw:rounded-box tw:bg-base-300/50 tw:p-3">
          <legend class="dui-fieldset-legend">
            {{ t("FVTT_SCENE_MERGER.Options.ContentTitle") }}
          </legend>
          <div class="tw:grid tw:gap-x-4 tw:gap-y-2 tw:sm:grid-cols-2">
            <label
              v-for="category in categories"
              :key="category"
              class="tw:flex tw:min-w-0 tw:items-start tw:justify-between tw:gap-2 tw:rounded-field tw:bg-base-200 tw:p-2"
            >
              <span class="tw:min-w-0">
                <span class="tw:block tw:text-sm tw:font-medium">{{
                  t(`FVTT_SCENE_MERGER.Options.Content.${category}.Label`)
                }}</span>
                <span class="tw:block tw:text-[0.68rem] tw:opacity-60">{{
                  t(`FVTT_SCENE_MERGER.Options.Content.${category}.Help`)
                }}</span>
                <span
                  v-if="CORE_CONTENT_CAPABILITIES[category] === 'unavailable'"
                  class="dui-badge dui-badge-warning dui-badge-soft dui-badge-xs tw:mt-1"
                >
                  {{ t("FVTT_SCENE_MERGER.Options.UnavailableV14") }}
                </span>
              </span>
              <input
                class="dui-toggle dui-toggle-sm"
                type="checkbox"
                :checked="store.content[category]"
                :disabled="
                  CORE_CONTENT_CAPABILITIES[category] === 'unavailable' || !store.setupEditable
                "
                @change="toggleContent(category, $event)"
              />
            </label>
          </div>
        </fieldset>

        <fieldset class="dui-fieldset tw:min-w-0 tw:rounded-box tw:bg-base-300/50 tw:p-3">
          <legend class="dui-fieldset-legend">
            {{ t("FVTT_SCENE_MERGER.Options.DestinationTitle") }}
          </legend>
          <label class="dui-label tw:pb-0 tw:text-xs" for="scene-merger-name">{{
            t("FVTT_SCENE_MERGER.Options.Name")
          }}</label>
          <input
            id="scene-merger-name"
            class="dui-input dui-input-sm tw:w-full"
            type="text"
            :value="store.destination.name"
            :disabled="!store.setupEditable"
            @change="textDestination"
          />

          <label class="dui-label tw:pb-0 tw:text-xs" for="scene-merger-folder">{{
            t("FVTT_SCENE_MERGER.Options.Folder")
          }}</label>
          <select
            id="scene-merger-folder"
            class="dui-select dui-select-sm tw:w-full"
            :value="store.destination.folderId ?? ''"
            :disabled="!store.setupEditable"
            @change="folderDestination"
          >
            <option value="">{{ t("FVTT_SCENE_MERGER.Selection.RootFolder") }}</option>
            <option v-for="folder in store.folderChoices" :key="folder.id" :value="folder.id">
              {{ folder.name }}
            </option>
          </select>

          <div class="tw:mt-2 tw:grid tw:gap-2">
            <label
              v-for="key in [
                'navigation',
                'openAfterMerge',
                'activateAfterMerge',
                'lockBackgroundTiles',
              ] as const"
              :key="key"
              class="tw:flex tw:items-center tw:justify-between tw:gap-3 tw:text-sm"
            >
              <span>
                <span class="tw:block">{{
                  t(`FVTT_SCENE_MERGER.Options.Destination.${key}.Label`)
                }}</span>
                <span class="tw:block tw:text-[0.68rem] tw:opacity-60">{{
                  t(`FVTT_SCENE_MERGER.Options.Destination.${key}.Help`)
                }}</span>
              </span>
              <input
                class="dui-checkbox dui-checkbox-sm"
                type="checkbox"
                :checked="store.destination[key]"
                :disabled="!store.setupEditable"
                @change="booleanDestination(key, $event)"
              />
            </label>
          </div>
        </fieldset>
      </div>
    </div>
  </section>
</template>
