import { createPinia } from "pinia";
import { type App as VueApp, type Component, createApp } from "vue";

export abstract class FoundryVueApplication extends foundry.applications.api.ApplicationV2 {
  #vueApp: undefined | VueApp<Element>;

  protected getVueProps(): Record<string, unknown> | undefined {
    return undefined;
  }

  protected abstract getVueComponent(): Component;

  protected override async _renderHTML(
    _context: foundry.applications.types.ApplicationRenderContext,
    _options: foundry.applications.types.ApplicationRenderOptions,
  ): Promise<HTMLElement> {
    const mountRoot = document.createElement("div");
    mountRoot.classList.add("fvtt-scene-merger-root");
    mountRoot.dataset["theme"] = "fvtt-scene-merger";

    return mountRoot;
  }

  protected override _replaceHTML(
    result: HTMLElement,
    content: HTMLElement,
    _options: foundry.applications.types.ApplicationRenderOptions,
  ): void {
    this.unmountVue();
    content.classList.add("fvtt-scene-merger-app");
    content.replaceChildren(result);

    this.#vueApp = createApp(this.getVueComponent(), this.getVueProps() ?? {});
    this.#vueApp.use(createPinia());
    this.#vueApp.mount(result);
  }

  protected override async _preClose(
    options: foundry.applications.types.ApplicationRenderOptions,
  ): Promise<void> {
    this.unmountVue();
    await super._preClose(options);
  }

  private unmountVue(): void {
    this.#vueApp?.unmount();
    this.#vueApp = undefined;
  }
}
