<script setup lang="ts">
/* eslint-disable vue/html-closing-bracket-newline, vue/html-indent, vue/html-self-closing -- Prettier owns Vue template formatting. */
import { computed, ref } from "vue";

import type { SceneMergerLocalizer } from "../../../../state/scene-merger";
import { useSceneMergerStore } from "../../../../state/scene-merger";

defineProps<{ readonly t: SceneMergerLocalizer }>();
const emit = defineEmits<{ locate: [sceneId: string] }>();
const store = useSceneMergerStore();
const query = ref("");

const filteredScenes = computed(() => {
  const needle = query.value.trim().toLocaleLowerCase();
  return store.availableScenes.filter((scene) => {
    if (store.selectedSceneIds.includes(scene.id)) return false;
    if (!needle) return true;
    return `${scene.name} ${scene.folderName ?? ""}`.toLocaleLowerCase().includes(needle);
  });
});

function dimensions(width: number, height: number): string {
  return `${width.toLocaleString()} × ${height.toLocaleString()}`;
}
</script>

<template>
  <aside class="dui-card dui-card-border tw:min-h-0 tw:bg-base-200">
    <div class="dui-card-body tw:min-h-0 tw:gap-3 tw:p-3">
      <div class="tw:flex tw:items-center tw:justify-between tw:gap-2">
        <div>
          <h2 class="dui-card-title tw:text-base">{{ t("FVTT_SCENE_MERGER.Selection.Title") }}</h2>
          <p class="tw:m-0 tw:text-xs tw:opacity-65">{{ t("FVTT_SCENE_MERGER.Selection.Help") }}</p>
        </div>
        <span class="dui-badge dui-badge-neutral dui-badge-sm">{{
          store.selectedScenes.length
        }}</span>
      </div>

      <label class="dui-input dui-input-sm tw:flex tw:w-full tw:items-center tw:gap-2">
        <span aria-hidden="true">⌕</span>
        <input
          v-model="query"
          class="tw:min-w-0 tw:flex-1"
          type="search"
          :disabled="!store.setupEditable"
          :placeholder="t('FVTT_SCENE_MERGER.Selection.Search')"
        />
      </label>

      <div
        class="scene-list-scroll tw:min-h-32 tw:flex-1 tw:overflow-auto tw:rounded-box tw:bg-base-300/60 tw:p-1"
      >
        <ul v-if="filteredScenes.length" class="dui-list tw:m-0 tw:list-none tw:gap-1 tw:p-0">
          <li
            v-for="scene in filteredScenes"
            :key="scene.id"
            class="dui-list-row tw:grid-cols-[3rem_minmax(0,1fr)_auto] tw:items-center tw:gap-2 tw:bg-base-200 tw:p-2"
          >
            <div class="tw:h-10 tw:w-12 tw:overflow-hidden tw:rounded-field tw:bg-neutral">
              <img
                v-if="scene.thumbnail"
                class="tw:h-full tw:w-full tw:object-cover"
                :src="scene.thumbnail"
                alt=""
              />
              <span
                v-else
                class="tw:flex tw:h-full tw:items-center tw:justify-center tw:text-xs tw:opacity-50"
                aria-hidden="true"
                >▧</span
              >
            </div>
            <div class="tw:min-w-0">
              <div class="tw:truncate tw:text-sm tw:font-semibold">{{ scene.name }}</div>
              <div class="tw:truncate tw:text-[0.7rem] tw:opacity-65">
                {{ scene.folderName ?? t("FVTT_SCENE_MERGER.Selection.RootFolder") }}
              </div>
              <div class="tw:text-[0.7rem] tw:opacity-65">
                {{ dimensions(scene.dimensions.sceneWidth, scene.dimensions.sceneHeight) }}
              </div>
              <div class="tw:text-[0.68rem] tw:opacity-60">
                {{
                  t("FVTT_SCENE_MERGER.Selection.GridDetails", {
                    type: scene.grid.type,
                    size: scene.grid.size,
                    distance: scene.grid.distance,
                    units: scene.grid.units,
                  })
                }}
              </div>
            </div>
            <button
              class="dui-btn dui-btn-sm dui-btn-square"
              type="button"
              :disabled="!store.setupEditable || !scene.canMerge"
              :aria-label="t('FVTT_SCENE_MERGER.Selection.AddNamed', { name: scene.name })"
              @click="store.addScene(scene.id)"
            >
              +
            </button>
          </li>
        </ul>
        <p v-else class="tw:m-3 tw:text-center tw:text-sm tw:opacity-60">
          {{ t("FVTT_SCENE_MERGER.Selection.NoMatches") }}
        </p>
      </div>

      <div class="tw:flex tw:items-center tw:justify-between tw:gap-2">
        <h3 class="tw:m-0 tw:text-sm tw:font-semibold">
          {{ t("FVTT_SCENE_MERGER.Selection.Selected") }}
        </h3>
        <button
          class="dui-btn dui-btn-ghost dui-btn-xs"
          type="button"
          :disabled="!store.setupEditable || store.selectedScenes.length === 0"
          @click="store.clearScenes()"
        >
          {{ t("FVTT_SCENE_MERGER.Actions.Clear") }}
        </button>
      </div>

      <ol class="dui-list tw:m-0 tw:max-h-56 tw:list-none tw:overflow-auto tw:p-0">
        <li
          v-for="(scene, index) in store.selectedScenes"
          :key="scene.id"
          class="dui-list-row tw:grid-cols-[1.5rem_minmax(0,1fr)_auto] tw:items-center tw:gap-1 tw:px-2 tw:py-1.5"
        >
          <span class="dui-badge dui-badge-ghost dui-badge-xs">{{ index + 1 }}</span>
          <div class="tw:min-w-0">
            <div class="tw:truncate tw:text-sm tw:font-medium">{{ scene.name }}</div>
            <div class="tw:text-[0.68rem] tw:opacity-60">
              {{ dimensions(scene.dimensions.sceneWidth, scene.dimensions.sceneHeight) }}
            </div>
          </div>
          <div class="tw:flex tw:gap-0.5">
            <button
              class="dui-btn dui-btn-ghost dui-btn-xs dui-btn-square"
              type="button"
              :disabled="!store.setupEditable || index === 0"
              :aria-label="t('FVTT_SCENE_MERGER.Actions.MoveUp')"
              @click="store.reorderScene(scene.id, -1)"
            >
              ↑
            </button>
            <button
              class="dui-btn dui-btn-ghost dui-btn-xs dui-btn-square"
              type="button"
              :disabled="!store.setupEditable || index === store.selectedScenes.length - 1"
              :aria-label="t('FVTT_SCENE_MERGER.Actions.MoveDown')"
              @click="store.reorderScene(scene.id, 1)"
            >
              ↓
            </button>
            <button
              class="dui-btn dui-btn-ghost dui-btn-xs dui-btn-square"
              type="button"
              :disabled="!store.setupEditable"
              :aria-label="t('FVTT_SCENE_MERGER.Actions.Locate')"
              @click="emit('locate', scene.id)"
            >
              ◎
            </button>
            <button
              class="dui-btn dui-btn-ghost dui-btn-xs dui-btn-square"
              type="button"
              :disabled="!store.setupEditable"
              :aria-label="t('FVTT_SCENE_MERGER.Selection.RemoveNamed', { name: scene.name })"
              @click="store.removeScene(scene.id)"
            >
              ×
            </button>
          </div>
        </li>
      </ol>
    </div>
  </aside>
</template>
