import { reactive, ref, type ComputedRef, type Ref } from "vue";

import {
  calculateZoomToFit,
  DEFAULT_SNAP_SETTINGS,
  zoomAroundPoint,
} from "../../functions/scene-merger";
import type {
  Bounds,
  Point,
  ScenePlacement,
  SnapMode,
  ViewportSize,
  WorkspaceView,
} from "../../types/scene-merger";

export function createWorkspaceState(
  placements: Ref<readonly ScenePlacement[]>,
  arrangementBounds: ComputedRef<Bounds>,
  canMutate: () => boolean = () => true,
) {
  const view = ref<WorkspaceView>({ panX: 24, panY: 24, zoom: 0.1 });
  const snap = reactive({ ...DEFAULT_SNAP_SETTINGS, mode: DEFAULT_SNAP_SETTINGS.mode as SnapMode });

  function setSnap(mode: SnapMode, interval?: number): void {
    if (!canMutate()) return;
    snap.mode = mode;
    if (interval !== undefined && Number.isFinite(interval) && interval > 0) {
      snap.pixelInterval = interval;
    }
  }

  function setView(next: WorkspaceView): void {
    if (!canMutate()) return;
    view.value = next;
  }

  function zoomAt(nextZoom: number, point: Point): void {
    if (!canMutate()) return;
    view.value = zoomAroundPoint(view.value, nextZoom, point);
  }

  function fitView(viewport: ViewportSize): void {
    if (!canMutate()) return;
    view.value = calculateZoomToFit(arrangementBounds.value, viewport, 36);
  }

  function resetView(): void {
    if (!canMutate()) return;
    view.value = { panX: 24, panY: 24, zoom: 0.1 };
  }

  function locateScene(sceneId: string, viewport: ViewportSize): void {
    if (!canMutate()) return;
    const item = placements.value.find((placement) => placement.sceneId === sceneId);
    if (!item) return;
    view.value = {
      ...view.value,
      panX: viewport.width / 2 - (item.x + item.width / 2) * view.value.zoom,
      panY: viewport.height / 2 - (item.y + item.height / 2) * view.value.zoom,
    };
  }

  return { fitView, locateScene, resetView, setSnap, setView, snap, view, zoomAt };
}
