export type ContentCategory =
  | "backgrounds"
  | "tiles"
  | "walls"
  | "lights"
  | "sounds"
  | "drawings"
  | "notes"
  | "regions"
  | "tokens"
  | "templates";

export type ContentSelection = Readonly<Record<ContentCategory, boolean>>;

export type ContentAvailability = "available" | "unavailable";

export type ContentCapabilities = Readonly<Record<ContentCategory, ContentAvailability>>;

export interface DestinationOptions {
  readonly activateAfterMerge: boolean;
  readonly folderId: string | null;
  readonly lockBackgroundTiles: boolean;
  readonly name: string;
  readonly navigation: boolean;
  readonly openAfterMerge: boolean;
}

export interface MergeOptions {
  readonly content: ContentSelection;
  readonly destination: DestinationOptions;
}

export const CORE_CONTENT_CAPABILITIES: ContentCapabilities = {
  backgrounds: "available",
  drawings: "available",
  lights: "available",
  notes: "available",
  regions: "available",
  sounds: "available",
  templates: "unavailable",
  tiles: "available",
  tokens: "available",
  walls: "available",
};
