import type { FoundryData, FoundrySceneDimensions } from "../../types/foundry";
import type { ScenePlacement, SceneSnapshot } from "../../types/scene-merger";
import { MODULE_ID } from "../constants";
import { asRecord, cloneRecord } from "./runtime-utils";

export function prepareBackgroundTiles(
  scenes: readonly SceneSnapshot[],
  placements: readonly ScenePlacement[],
  destination: FoundrySceneDimensions & { readonly levelId: string },
  locked: boolean,
): readonly FoundryData[] {
  const placementById = new Map(placements.map((placement) => [placement.sceneId, placement]));
  const stackById = new Map(
    [...placements]
      .sort((left, right) => left.order - right.order)
      .map((placement, index) => [placement.sceneId, index]),
  );
  const stackStride = Math.max(1, ...scenes.map((scene) => scene.documents.Tile?.length ?? 0)) + 1;
  const elevationBands = calculateContentElevationBands(scenes);
  const tiles: FoundryData[] = [];

  for (const scene of scenes) {
    const placement = placementById.get(scene.id);
    const stack = stackById.get(scene.id) ?? 0;
    const level = scene.documents.Level?.[0];
    if (!placement || !level) continue;
    const textures = asRecord(level["textures"]) ?? {};
    addLayerTile(
      tiles,
      "background",
      asRecord(level["background"]),
      textures,
      scene,
      placement,
      destination,
      locked,
      elevationBands.background,
      -(placements.length * 2) + stack,
    );
    addLayerTile(
      tiles,
      "foreground",
      asRecord(level["foreground"]),
      textures,
      scene,
      placement,
      destination,
      locked,
      elevationBands.foreground,
      (placements.length + 1) * stackStride + stack,
    );
  }
  return tiles;
}

function addLayerTile(
  output: FoundryData[],
  layerName: "background" | "foreground",
  layer: FoundryData | undefined,
  textures: FoundryData,
  scene: SceneSnapshot,
  placement: ScenePlacement,
  destination: FoundrySceneDimensions & { readonly levelId: string },
  locked: boolean,
  elevation: number,
  sort: number,
): void {
  if (typeof layer?.["src"] !== "string" || layer["src"].length === 0) return;
  const texture = { ...cloneRecord(textures), ...cloneRecord(layer) };
  delete texture["color"];
  output.push({
    alpha: 1,
    anchorX: 0,
    anchorY: 0,
    elevation,
    flags: {
      [MODULE_ID]: {
        importedLevelTexture: {
          layer: layerName,
          sourceLevelId: scene.levels[0]?.id ?? null,
          sourceSceneId: scene.id,
        },
      },
    },
    height: placement.height,
    hidden: false,
    levels: [destination.levelId],
    locked,
    name: `${scene.name} — ${layerName}`,
    rotation: 0,
    sort,
    texture,
    width: placement.width,
    x: destination.sceneX + placement.x,
    y: destination.sceneY + placement.y,
  });
}

function calculateContentElevationBands(scenes: readonly SceneSnapshot[]): {
  readonly background: number;
  readonly foreground: number;
} {
  let minimum = 0;
  let maximum = 0;
  const include = (value: unknown): void => {
    if (typeof value !== "number" || !Number.isFinite(value)) return;
    minimum = Math.min(minimum, value);
    maximum = Math.max(maximum, value);
  };

  for (const scene of scenes) {
    for (const level of scene.levels) {
      include(level.elevation.bottom);
      include(level.elevation.top);
    }
    for (const documents of Object.values(scene.documents)) {
      for (const document of documents ?? []) include(document["elevation"]);
    }
  }
  return {
    background: Math.max(-Number.MAX_VALUE, minimum - 1),
    foreground: Math.min(Number.MAX_VALUE, maximum + 1),
  };
}
