import { MODULE_ID, MODULE_TITLE } from "../constants";

function debuggingEnabled(): boolean {
  try {
    return game?.settings.get(MODULE_ID, "debugLogging") === true;
  } catch {
    return false;
  }
}

export const logger = {
  debug(message: string, details?: unknown): void {
    if (!debuggingEnabled()) return;
    console.debug(`${MODULE_TITLE} | ${message}`, details ?? "");
  },
  error(message: string, details?: unknown): void {
    console.error(`${MODULE_TITLE} | ${message}`, details ?? "");
  },
  info(message: string, details?: unknown): void {
    console.info(`${MODULE_TITLE} | ${message}`, details ?? "");
  },
  warn(message: string, details?: unknown): void {
    console.warn(`${MODULE_TITLE} | ${message}`, details ?? "");
  },
};
