import type {
  FoundryData,
  FoundryDocument,
  FoundryScene,
  FoundrySceneDimensions,
} from "../../../types/foundry";
import { errorMessage } from "../runtime-utils";

export interface DestinationSceneHandle {
  readonly dimensions: FoundrySceneDimensions;
  readonly id: string;
  readonly levelId: string;
  readonly name: string;
  activate(): Promise<void>;
  createDocuments(type: string, data: FoundryData[]): Promise<FoundryDocument[]>;
  delete(): Promise<void>;
  open(): Promise<void>;
  updateDocuments(type: string, data: FoundryData[]): Promise<FoundryDocument[]>;
}

export interface SceneMergeRuntime {
  callHook(hook: string, ...args: unknown[]): void;
  createDestination(data: FoundryData): Promise<DestinationSceneHandle>;
  notifyError(message: string): void;
  notifyInfo(message: string): void;
}

export type SceneFactory = (data: FoundryData) => Promise<FoundryScene | undefined>;

class FoundryDestinationScene implements DestinationSceneHandle {
  readonly #scene: FoundryScene;

  constructor(scene: FoundryScene) {
    const sceneId = scene.id;
    const levelId = scene.levels.contents[0]?.id;
    if (!sceneId || !levelId || scene.levels.size !== 1) {
      throw new Error("Foundry did not create the expected destination Scene and Level.");
    }
    this.#scene = scene;
    this.id = sceneId;
    this.levelId = levelId;
  }

  get dimensions(): FoundrySceneDimensions {
    return this.#scene.dimensions;
  }

  get name(): string {
    return this.#scene.name ?? "Merged Scene";
  }

  readonly id: string;
  readonly levelId: string;

  async activate(): Promise<void> {
    await this.#scene.activate({ pullUsers: false });
  }

  async createDocuments(type: string, data: FoundryData[]): Promise<FoundryDocument[]> {
    return this.#scene.createEmbeddedDocuments(type, data);
  }

  async delete(): Promise<void> {
    await this.#scene.delete();
  }

  async open(): Promise<void> {
    await this.#scene.view();
  }

  async updateDocuments(type: string, data: FoundryData[]): Promise<FoundryDocument[]> {
    return this.#scene.updateEmbeddedDocuments(type, data, {
      diff: false,
      recursive: false,
    });
  }
}

export async function createFoundryDestination(
  data: FoundryData,
  createScene: SceneFactory = (sceneData) => Scene.implementation.create(sceneData),
): Promise<DestinationSceneHandle> {
  const scene = await createScene(data);
  if (!scene) {
    throw new Error("Foundry did not return a destination Scene after creation.");
  }
  try {
    return new FoundryDestinationScene(scene);
  } catch (error) {
    try {
      await scene.delete();
    } catch (cleanupError) {
      throw new Error(
        `${errorMessage(error)} Cleanup of the invalid Scene${scene.id ? ` ${scene.id}` : ""} also failed: ${errorMessage(cleanupError)}`,
        { cause: cleanupError },
      );
    }
    throw error;
  }
}

export const foundryMergeRuntime: SceneMergeRuntime = {
  callHook(hook, ...args) {
    Hooks.callAll(hook, ...args);
  },
  createDestination: createFoundryDestination,
  notifyError(message) {
    ui?.notifications?.error(message);
  },
  notifyInfo(message) {
    ui?.notifications?.info(message);
  },
};
