import type {
  Point,
  RegionDocumentData,
  RegionGridOffset,
  RegionShapeBaseData,
  RegionShapeData,
} from "../../../types/scene-merger";

import { cloneData } from "./clone";

const PIXEL_ORIGIN_SHAPES = new Set(["circle", "cone", "ellipse", "line", "rectangle", "ring"]);

export interface RegionGridTransform {
  readonly size: number;
  readonly type: number;
}

function translateXY<T extends RegionShapeBaseData>(value: T, delta: Point): T {
  const translated: Record<string, unknown> = { ...cloneData(value) };
  if (typeof value.x === "number") translated["x"] = value.x + delta.x;
  if (typeof value.y === "number") translated["y"] = value.y + delta.y;
  return translated as T;
}

function translateAbsolutePoints(points: readonly number[], delta: Point): readonly number[] {
  return points.map((coordinate, index) => coordinate + (index % 2 === 0 ? delta.x : delta.y));
}

function translateGridOffsets(
  offsets: readonly RegionGridOffset[],
  delta: Point,
  grid: RegionGridTransform | undefined,
): readonly RegionGridOffset[] {
  if (!grid || grid.type !== 1 || grid.size <= 0) {
    throw new Error("Grid Region shapes can currently be translated only on a square grid.");
  }

  const rowShift = delta.y / grid.size;
  const columnShift = delta.x / grid.size;
  if (!Number.isInteger(rowShift) || !Number.isInteger(columnShift)) {
    throw new Error("Grid Region shape translation must align to complete grid cells.");
  }

  return offsets.map((offset) => ({
    ...cloneData(offset),
    i: offset.i + rowShift,
    j: offset.j + columnShift,
  }));
}

export function translateRegionShape<T extends RegionShapeData>(
  shape: T,
  delta: Point,
  grid?: RegionGridTransform,
): T {
  const translated: Record<string, unknown> = { ...cloneData(shape) };

  if (PIXEL_ORIGIN_SHAPES.has(shape.type)) {
    return translateXY(translated as T, delta);
  }

  if (shape.type === "polygon") {
    translated["points"] = translateAbsolutePoints(shape.points ?? [], delta);
    return translated as T;
  }

  if (shape.type === "emanation") {
    if (shape.base) translated["base"] = translateXY(shape.base, delta);
    return translated as T;
  }

  if (shape.type === "grid") {
    translated["offsets"] = translateGridOffsets(shape.offsets ?? [], delta, grid);
    return translated as T;
  }

  if (shape.type === "token") {
    throw new Error("Token-linked Region shapes cannot currently be merged safely.");
  }

  throw new Error(`Unsupported Region shape type: ${shape.type}`);
}

export function translateRegionDocument<T extends RegionDocumentData>(
  data: T,
  delta: Point,
  grid?: RegionGridTransform,
): T {
  const attachment = data.attachment?.["token"];
  if (typeof attachment === "string" && attachment.length > 0) {
    throw new Error("Attached Regions cannot currently be merged safely.");
  }

  const clone = cloneData(data);
  return {
    ...clone,
    _shapeConstraints: null,
    shapes: data.shapes?.map((shape) => translateRegionShape(shape, delta, grid)) ?? [],
  };
}
