import type {
  Point,
  Rectangle,
  SceneDimensions,
  ScenePlacement,
} from "../../../types/scene-merger";

export function translatePoint(point: Point, delta: Point): Point {
  return { x: point.x + delta.x, y: point.y + delta.y };
}

export function translateRectangle(rectangle: Rectangle, delta: Point): Rectangle {
  return { ...rectangle, ...translatePoint(rectangle, delta) };
}

export function calculateDocumentDelta(
  source: SceneDimensions,
  destination: SceneDimensions,
  placement: Pick<ScenePlacement, "x" | "y">,
): Point {
  return {
    x: destination.sceneX + placement.x - source.sceneX,
    y: destination.sceneY + placement.y - source.sceneY,
  };
}

export function isGridTranslationAligned(delta: Point, gridSize: number): boolean {
  if (!Number.isFinite(gridSize) || gridSize <= 0) {
    return false;
  }

  const epsilon = 1e-7;
  const xCells = delta.x / gridSize;
  const yCells = delta.y / gridSize;

  return (
    Math.abs(xCells - Math.round(xCells)) < epsilon &&
    Math.abs(yCells - Math.round(yCells)) < epsilon
  );
}
