<script setup lang="ts">
/* eslint-disable vue/html-closing-bracket-newline, vue/html-indent, vue/html-self-closing -- Prettier owns Vue template formatting. */
import { computed, ref } from "vue";

import type { SceneMergerLocalizer } from "../../../../state/scene-merger";
import { useSceneMergerStore } from "../../../../state/scene-merger";
import type { ScenePlacement, ViewportSize } from "../../../../types/scene-merger";

defineProps<{ readonly t: SceneMergerLocalizer }>();
const store = useSceneMergerStore();
const workspace = ref<HTMLElement | null>(null);

type PointerOperation =
  | { kind: "pan"; panX: number; panY: number; pointerId: number; startX: number; startY: number }
  | {
      kind: "scene";
      originX: number;
      originY: number;
      pointerId: number;
      sceneId: string;
      startX: number;
      startY: number;
    };

const operation = ref<PointerOperation | null>(null);
const sceneById = computed(() => new Map(store.availableScenes.map((scene) => [scene.id, scene])));
const overlappingIds = computed(
  () => new Set(store.overlaps.flatMap((item) => [item.firstSceneId, item.secondSceneId])),
);
const viewport = computed<ViewportSize>(() => ({
  height: workspace.value?.clientHeight ?? 480,
  width: workspace.value?.clientWidth ?? 800,
}));

function rectangleStyle(placement: ScenePlacement): Record<string, string | number> {
  return {
    height: `${Math.max(8, placement.height * store.view.zoom)}px`,
    left: `${store.view.panX + placement.x * store.view.zoom}px`,
    top: `${store.view.panY + placement.y * store.view.zoom}px`,
    width: `${Math.max(8, placement.width * store.view.zoom)}px`,
    zIndex: placement.order + 2,
  };
}

const boundsStyle = computed(() => ({
  height: `${store.arrangementBounds.height * store.view.zoom}px`,
  left: `${store.view.panX + store.arrangementBounds.minX * store.view.zoom}px`,
  top: `${store.view.panY + store.arrangementBounds.minY * store.view.zoom}px`,
  width: `${store.arrangementBounds.width * store.view.zoom}px`,
}));

const workspaceStyle = computed(() => ({
  backgroundPosition: `${store.view.panX}px ${store.view.panY}px`,
  backgroundSize: `${Math.max(12, 100 * store.view.zoom)}px ${Math.max(12, 100 * store.view.zoom)}px`,
}));

function capture(event: PointerEvent): void {
  (event.currentTarget as HTMLElement).setPointerCapture(event.pointerId);
}

function startPan(event: PointerEvent): void {
  if (event.button !== 0) return;
  capture(event);
  operation.value = {
    kind: "pan",
    panX: store.view.panX,
    panY: store.view.panY,
    pointerId: event.pointerId,
    startX: event.clientX,
    startY: event.clientY,
  };
}

function startSceneDrag(event: PointerEvent, placement: ScenePlacement): void {
  if (event.button !== 0) return;
  event.stopPropagation();
  capture(event);
  operation.value = {
    kind: "scene",
    originX: placement.x,
    originY: placement.y,
    pointerId: event.pointerId,
    sceneId: placement.sceneId,
    startX: event.clientX,
    startY: event.clientY,
  };
}

function movePointer(event: PointerEvent): void {
  const active = operation.value;
  if (!active || active.pointerId !== event.pointerId) return;
  const deltaX = event.clientX - active.startX;
  const deltaY = event.clientY - active.startY;
  if (active.kind === "pan") {
    store.setView({
      zoom: store.view.zoom,
      panX: active.panX + deltaX,
      panY: active.panY + deltaY,
    });
  } else {
    store.moveScene(
      active.sceneId,
      active.originX + deltaX / store.view.zoom,
      active.originY + deltaY / store.view.zoom,
      false,
    );
  }
}

function endPointer(event: PointerEvent): void {
  const active = operation.value;
  if (!active || active.pointerId !== event.pointerId) return;
  if (active.kind === "scene") {
    const placement = store.placements.find(({ sceneId }) => sceneId === active.sceneId);
    if (placement) store.moveScene(active.sceneId, placement.x, placement.y, true);
    void store.validateNow();
  }
  operation.value = null;
}

function wheel(event: WheelEvent): void {
  const bounds = workspace.value?.getBoundingClientRect();
  if (!bounds) return;
  store.zoomAt(store.view.zoom * (event.deltaY < 0 ? 1.14 : 0.88), {
    x: event.clientX - bounds.left,
    y: event.clientY - bounds.top,
  });
}

function nudge(event: KeyboardEvent, placement: ScenePlacement): void {
  const delta = event.shiftKey ? 50 : 10;
  const directions: Record<string, readonly [number, number]> = {
    ArrowDown: [0, delta],
    ArrowLeft: [-delta, 0],
    ArrowRight: [delta, 0],
    ArrowUp: [0, -delta],
  };
  const direction = directions[event.key];
  if (!direction) return;
  event.preventDefault();
  store.moveScene(placement.sceneId, placement.x + direction[0], placement.y + direction[1], true);
  void store.validateNow();
}

function fit(): void {
  store.fitView(viewport.value);
}
function reset(): void {
  store.resetView();
}
function locate(sceneId: string): void {
  store.locateScene(sceneId, viewport.value);
}
function zoom(factor: number): void {
  store.zoomAt(store.view.zoom * factor, {
    x: viewport.value.width / 2,
    y: viewport.value.height / 2,
  });
}

defineExpose({ fit, locate, reset, zoom });
</script>

<template>
  <div
    ref="workspace"
    class="layout-workspace tw:relative tw:min-h-[440px] tw:touch-none tw:overflow-hidden tw:rounded-box tw:border tw:border-base-300 tw:bg-base-100 tw:select-none"
    :class="{ 'tw:pointer-events-none tw:opacity-70': !store.setupEditable }"
    :aria-disabled="!store.setupEditable"
    :style="workspaceStyle"
    @pointerdown="startPan"
    @pointermove="movePointer"
    @pointerup="endPointer"
    @pointercancel="endPointer"
    @wheel.prevent="wheel"
  >
    <div
      v-if="store.placements.length"
      class="layout-total-bounds tw:pointer-events-none tw:absolute tw:border tw:border-dashed tw:border-accent/70"
      :style="boundsStyle"
    >
      <span
        class="tw:absolute tw:-top-6 tw:left-0 tw:whitespace-nowrap tw:text-[0.68rem] tw:text-accent"
      >
        {{ t("FVTT_SCENE_MERGER.Layout.TotalBounds") }}
      </span>
    </div>

    <button
      v-for="placement in store.placements"
      :key="placement.sceneId"
      class="layout-scene tw:absolute tw:overflow-hidden tw:rounded-field tw:border-2 tw:border-secondary tw:bg-neutral tw:p-0 tw:text-left tw:text-neutral-content tw:shadow-lg tw:focus:outline-2 tw:focus:outline-accent"
      :class="{ 'layout-scene-overlap': overlappingIds.has(placement.sceneId) }"
      :style="rectangleStyle(placement)"
      type="button"
      :disabled="!store.setupEditable"
      :aria-label="
        t('FVTT_SCENE_MERGER.Layout.DragScene', {
          name: sceneById.get(placement.sceneId)?.name ?? placement.sceneId,
        })
      "
      @pointerdown="startSceneDrag($event, placement)"
      @keydown="nudge($event, placement)"
    >
      <img
        v-if="sceneById.get(placement.sceneId)?.thumbnail"
        class="tw:absolute tw:inset-0 tw:h-full tw:w-full tw:object-cover tw:opacity-45"
        :src="sceneById.get(placement.sceneId)?.thumbnail ?? ''"
        alt=""
        draggable="false"
      />
      <span class="tw:absolute tw:inset-0 tw:bg-neutral/30" />
      <span class="tw:absolute tw:inset-x-2 tw:top-1.5 tw:min-w-0">
        <strong class="tw:block tw:truncate tw:text-xs">{{
          sceneById.get(placement.sceneId)?.name
        }}</strong>
        <small class="tw:block tw:truncate tw:text-[0.65rem] tw:opacity-80"
          >{{ placement.width }} × {{ placement.height }}</small
        >
      </span>
      <span
        class="tw:absolute tw:right-1.5 tw:bottom-1 tw:rounded-field tw:bg-neutral/80 tw:px-1.5 tw:py-0.5 tw:text-[0.62rem]"
      >
        {{ Math.round(placement.x) }}, {{ Math.round(placement.y) }}
      </span>
    </button>

    <div
      v-if="store.placements.length === 0"
      class="tw:pointer-events-none tw:absolute tw:inset-0 tw:flex tw:items-center tw:justify-center tw:p-8 tw:text-center tw:text-sm tw:opacity-60"
    >
      {{ t("FVTT_SCENE_MERGER.Layout.Empty") }}
    </div>
    <div
      class="tw:pointer-events-none tw:absolute tw:right-2 tw:bottom-2 tw:rounded-field tw:bg-base-300/85 tw:px-2 tw:py-1 tw:text-[0.65rem] tw:opacity-75"
    >
      {{ t("FVTT_SCENE_MERGER.Layout.PanZoomHint") }}
    </div>
  </div>
</template>
