import type { FoundryData } from "../../../types/foundry";
import type {
  CoreDocumentType,
  MergeProgress,
  MergeStage,
  SourceDocumentKey,
} from "../../../types/scene-merger";
import { logger } from "../../logging/logger";
import { recordCreatedIds } from "../provenance";
import { yieldToBrowser } from "../runtime-utils";
import type { CancellationCheckpoint } from "./errors";
import type { DestinationSceneHandle } from "./foundry-runtime";

interface BatchConfiguration {
  readonly onProgress?: (progress: MergeProgress) => void;
}

export async function createUnmappedBatches(
  destination: DestinationSceneHandle,
  type: CoreDocumentType,
  data: readonly FoundryData[],
  stage: MergeStage,
  configuration: BatchConfiguration,
  cancellation: CancellationCheckpoint,
  batchSize: number,
): Promise<void> {
  await forEachBatch(data, batchSize, cancellation, async (batch, completed) => {
    const created = await destination.createDocuments(type, batch);
    if (created.length !== batch.length) {
      throw new Error(
        `Foundry created ${created.length} of ${batch.length} requested ${type} documents.`,
      );
    }
    report(configuration, stage, completed, data.length, `Created ${type} documents`);
  });
}

export async function createMappedBatches(
  destination: DestinationSceneHandle,
  type: CoreDocumentType,
  data: readonly FoundryData[],
  idMap: Map<SourceDocumentKey, string>,
  unresolved: string[],
  stage: MergeStage,
  configuration: BatchConfiguration,
  cancellation: CancellationCheckpoint,
  batchSize: number,
): Promise<number> {
  let createdCount = 0;
  await forEachBatch(data, batchSize, cancellation, async (batch, completed) => {
    const created = await destination.createDocuments(type, batch);
    if (created.length !== batch.length) {
      throw new Error(
        `Foundry created ${created.length} of ${batch.length} requested ${type} documents.`,
      );
    }
    createdCount += created.length;
    const provenanceIssues = recordCreatedIds(created, idMap);
    if (provenanceIssues.length > 0) {
      unresolved.push(...provenanceIssues);
      throw new Error(
        `Foundry created ${type} documents without the provenance needed for safe ID mapping.`,
      );
    }
    report(configuration, stage, completed, data.length, `Created ${type} documents`);
  });
  return createdCount;
}

export async function updateBatches(
  destination: DestinationSceneHandle,
  type: CoreDocumentType,
  data: readonly FoundryData[],
  configuration: BatchConfiguration,
  cancellation: CancellationCheckpoint,
  batchSize: number,
): Promise<void> {
  await forEachBatch(data, batchSize, cancellation, async (batch, completed) => {
    const updated = await destination.updateDocuments(type, batch);
    if (updated.length !== batch.length) {
      throw new Error(
        `Foundry updated ${updated.length} of ${batch.length} requested ${type} documents.`,
      );
    }
    report(
      configuration,
      "rewritingReferences",
      completed,
      data.length,
      `Finalized ${type} references`,
    );
  });
}

export function report(
  configuration: BatchConfiguration,
  stage: MergeStage,
  completed: number,
  total: number,
  detail: string,
): void {
  logger.debug("Merge progress", { completed, detail, stage, total });
  configuration.onProgress?.({ completed, detail, stage, total });
}

async function forEachBatch(
  data: readonly FoundryData[],
  batchSize: number,
  cancellation: CancellationCheckpoint,
  operation: (batch: FoundryData[], completed: number) => Promise<void>,
): Promise<void> {
  for (let start = 0; start < data.length; start += batchSize) {
    cancellation.throwIfCancelled();
    const batch = data.slice(start, start + batchSize);
    await operation(batch, Math.min(start + batch.length, data.length));
    cancellation.throwIfCancelled();
    await yieldToBrowser();
  }
}
