import {
  createSourceDocumentKey,
  normalizePlacements,
  shouldCleanupPartialDestination,
} from "../../../functions/scene-merger";
import type { FoundryData } from "../../../types/foundry";
import type {
  CoreDocumentType,
  MergeFailureStage,
  MergeProgress,
  MergeRequest,
  MergeStage,
  MergeSummary,
  SceneSnapshot,
  SourceDocumentKey,
} from "../../../types/scene-merger";
import { runPostMergeExtensions, runPreMergeExtensions } from "../../extensions/extension-registry";
import { prepareBackgroundTiles } from "../background-tiles";
import {
  createMappedBatches,
  createUnmappedBatches,
  report as progress,
  updateBatches,
} from "./batches";
import type { CancellationCheckpoint } from "./errors";
import { MergeCancellation, SceneMergeError } from "./errors";
import type { DestinationSceneHandle, SceneMergeRuntime } from "./foundry-runtime";
import {
  assertActualGridAlignment,
  countRegionBehaviors,
  countSkippedDocuments,
  createSummary,
} from "./workflow-data";
import { prepareDocuments } from "../prepare-documents";
import { prepareReferenceUpdates } from "../reference-updates";
import { asRecord, cloneRecord, numeric } from "../runtime-utils";

const DEFAULT_BATCH_SIZE = 200;
const COPY_PLAN: readonly [CoreDocumentType, MergeStage][] = [
  ["Tile", "copyingTiles"],
  ["Wall", "copyingWalls"],
  ["AmbientLight", "copyingLights"],
  ["AmbientSound", "copyingSounds"],
  ["Drawing", "copyingDrawings"],
  ["Note", "copyingNotes"],
  ["Region", "copyingRegions"],
  ["Token", "copyingTokens"],
];

export interface MergeWorkflowConfiguration {
  readonly batchSize?: number;
  readonly cancellation?: CancellationCheckpoint;
  readonly cleanupPartial: boolean;
  readonly onProgress?: (progress: MergeProgress) => void;
  readonly runtime: SceneMergeRuntime;
  readonly validationWarnings?: readonly string[];
}

export async function runMergeWorkflow(
  request: MergeRequest,
  scenes: readonly SceneSnapshot[],
  configuration: MergeWorkflowConfiguration,
): Promise<MergeSummary> {
  const cancellation = configuration.cancellation ?? new MergeCancellation();
  const batchSize = Math.max(1, configuration.batchSize ?? DEFAULT_BATCH_SIZE);
  let destination: DestinationSceneHandle | undefined;
  let stage: MergeFailureStage = "beforeDestination";

  try {
    cancellation.throwIfCancelled();
    await runPreMergeExtensions(request);
    configuration.runtime.callHook("fvttSceneMergerPreMerge", request, scenes);
    stage = "calculatingBounds";
    progress(configuration, stage, 0, 1, "Calculating normalized destination bounds");
    const layout = normalizePlacements(request.placements);
    cancellation.throwIfCancelled();

    stage = "creatingScene";
    progress(configuration, stage, 0, 1, "Creating destination Scene and Level");
    destination = await configuration.runtime.createDestination(
      destinationSceneData(request, scenes, layout.width, layout.height),
    );
    progress(configuration, stage, 1, 1, destination.name);
    cancellation.throwIfCancelled();
    assertActualGridAlignment(scenes, layout.placements, destination);

    const idMap = createLevelIdMap(scenes, destination.levelId);
    const copied: Partial<Record<CoreDocumentType, number>> = { Level: 1 };
    const unresolved: string[] = [];
    stage = "creatingBackgrounds";
    progress(configuration, stage, 0, 0, "Preparing background and foreground Tiles");
    if (request.options.content.backgrounds) {
      const backgrounds = prepareBackgroundTiles(
        scenes,
        layout.placements,
        { ...destination.dimensions, levelId: destination.levelId },
        request.options.destination.lockBackgroundTiles,
      );
      await createUnmappedBatches(
        destination,
        "Tile",
        backgrounds,
        stage,
        configuration,
        cancellation,
        batchSize,
      );
      copied.Tile = backgrounds.length;
    }

    const prepared = prepareDocuments(
      scenes,
      layout.placements,
      { ...destination.dimensions, id: destination.id, levelId: destination.levelId },
      request,
      (data, context) =>
        configuration.runtime.callHook("fvttSceneMergerTransformDocument", data, context),
    );
    const skipped = countSkippedDocuments(scenes, request, prepared.skipped);

    for (const [type, copyStage] of COPY_PLAN) {
      stage = copyStage;
      const batch = prepared.batches.get(type) ?? [];
      progress(configuration, stage, 0, batch.length, `Preparing ${type} documents`);
      const createdCount = await createMappedBatches(
        destination,
        type,
        batch.map((entry) => entry.creationData),
        idMap,
        unresolved,
        stage,
        configuration,
        cancellation,
        batchSize,
      );
      copied[type] = (copied[type] ?? 0) + createdCount;
      if (type === "Region")
        copied.RegionBehavior = countRegionBehaviors(batch.map((entry) => entry.data));
    }

    stage = "rewritingReferences";
    progress(configuration, stage, 0, 0, "Rewriting supported internal references");
    const referenceUpdates = prepareReferenceUpdates(
      prepared.batches,
      idMap,
      destination.id,
      request.sourceSceneIds,
      (data, context) =>
        configuration.runtime.callHook("fvttSceneMergerRewriteReferences", data, context),
    );
    unresolved.push(...referenceUpdates.unresolved);
    for (const [type, updates] of referenceUpdates.updates) {
      await updateBatches(destination, type, updates, configuration, cancellation, batchSize);
    }

    stage = "finalizing";
    progress(configuration, stage, 0, 1, "Finalizing destination Scene");
    const summary = createSummary(
      scenes,
      destination,
      copied,
      skipped,
      referenceUpdates.referencesRewritten,
      unresolved,
      configuration.validationWarnings ?? [],
    );
    if (request.options.destination.activateAfterMerge) await destination.activate();
    if (request.options.destination.openAfterMerge) await destination.open();
    await runPostMergeExtensions(summary);
    configuration.runtime.callHook("fvttSceneMergerPostMerge", summary);
    progress(configuration, stage, 1, 1, destination.name);
    return summary;
  } catch (error) {
    let cleanupError: unknown;
    let destinationRemains = Boolean(destination);
    if (
      destination &&
      shouldCleanupPartialDestination({
        cleanupEnabled: configuration.cleanupPartial,
        destinationCreated: true,
        stage,
      })
    ) {
      try {
        await destination.delete();
        destinationRemains = false;
      } catch (cleanupFailure) {
        cleanupError = cleanupFailure;
      }
    }
    throw new SceneMergeError({
      ...(cleanupError ? { cleanupError } : {}),
      ...(destination && destinationRemains ? { destinationSceneId: destination.id } : {}),
      error,
      stage,
    });
  }
}

function destinationSceneData(
  request: MergeRequest,
  scenes: readonly SceneSnapshot[],
  width: number,
  height: number,
): FoundryData {
  const source = scenes[0];
  if (!source) throw new Error("No source Scene is available for destination settings.");
  const elevation = {
    bottom: Math.min(...scenes.map((scene) => scene.levels[0]?.elevation.bottom ?? 0)),
    top: Math.max(...scenes.map((scene) => scene.levels[0]?.elevation.top ?? 0)),
  };
  return {
    active: false,
    backgroundColor: source.source["backgroundColor"] ?? null,
    environment: cloneRecord(asRecord(source.source["environment"]) ?? {}),
    flags: { "fvtt-scene-merger": { sourceSceneIds: [...request.sourceSceneIds] } },
    folder: request.options.destination.folderId,
    grid: cloneRecord(asRecord(source.source["grid"]) ?? {}),
    height,
    levels: [{ elevation, name: "Merged Level" }],
    name: request.options.destination.name.trim() || "Merged Scene",
    navigation: request.options.destination.navigation,
    padding: numeric(source.source["padding"], 0.25),
    shiftX: 0,
    shiftY: 0,
    thumb: null,
    tokenVision: source.source["tokenVision"] ?? true,
    width,
  };
}

function createLevelIdMap(
  scenes: readonly SceneSnapshot[],
  destinationLevelId: string,
): Map<SourceDocumentKey, string> {
  const map = new Map<SourceDocumentKey, string>();
  for (const scene of scenes) {
    const levelId = scene.levels[0]?.id;
    if (!levelId) continue;
    const key = createSourceDocumentKey(scene.id, "Level", levelId);
    map.set(key, destinationLevelId);
  }
  return map;
}
