import type { Component } from "vue";

import type { LocalizeValues } from "../../../state/scene-merger";
import SceneMergerApp from "../../../view/apps/scene-merger/SceneMergerApp.vue";
import { sceneMergerService } from "../../runtime/scene-merger-service";
import { requireGame } from "../../runtime/runtime-utils";
import { I18N_PREFIX, MODULE_ID } from "../../constants";
import { FoundryVueApplication } from "../FoundryVueApplication";

export class SceneMergerApplication extends FoundryVueApplication {
  static override DEFAULT_OPTIONS = {
    id: `${MODULE_ID}-application`,
    position: {
      height: 900,
      width: 1240,
    },
    tag: "section",
    window: {
      icon: "fa-solid fa-object-group",
      resizable: true,
      title: `${I18N_PREFIX}.App.Title`,
    },
  };

  static async open(): Promise<void> {
    const registered = foundry.applications.instances.get(`${MODULE_ID}-application`);
    if (registered instanceof SceneMergerApplication) {
      if (registered.rendered) {
        registered.bringToFront();
        return;
      }
      await registered.render({ force: true });
      return;
    }
    await new SceneMergerApplication().render({ force: true });
  }

  protected override getVueComponent(): Component {
    return SceneMergerApp;
  }

  protected override getVueProps(): Record<string, unknown> {
    return {
      services: sceneMergerService,
      t: (key: string, values?: LocalizeValues) => {
        const i18n = requireGame().i18n;
        return values ? i18n.format(key, values) : i18n.localize(key);
      },
    };
  }
}

export async function openSceneMergerApplication(): Promise<void> {
  await SceneMergerApplication.open();
}
