<script setup lang="ts">
/* eslint-disable vue/html-closing-bracket-newline, vue/html-indent -- Prettier owns Vue template formatting. */
import { nextTick, ref, watch } from "vue";

import type { SceneMergerLocalizer } from "../../../../state/scene-merger";
import { useSceneMergerStore } from "../../../../state/scene-merger";
import LayoutToolbar from "./LayoutToolbar.vue";
import WorkspaceCanvas from "./WorkspaceCanvas.vue";

defineProps<{ readonly t: SceneMergerLocalizer }>();
const store = useSceneMergerStore();
const workspaceComponent = ref<InstanceType<typeof WorkspaceCanvas> | null>(null);

watch(
  () => store.placements.length,
  async (count, previous) => {
    if (count > 0 && previous === 0) {
      await nextTick();
      workspaceComponent.value?.fit();
    }
  },
);

function locateScene(sceneId: string): void {
  workspaceComponent.value?.locate(sceneId);
}
defineExpose({ locateScene });
</script>

<template>
  <section class="dui-card dui-card-border tw:min-w-0 tw:bg-base-200">
    <div class="dui-card-body tw:gap-3 tw:p-3">
      <div class="tw:flex tw:flex-wrap tw:items-start tw:justify-between tw:gap-2">
        <div>
          <h2 class="dui-card-title tw:text-base">{{ t("FVTT_SCENE_MERGER.Layout.Title") }}</h2>
          <p class="tw:m-0 tw:text-xs tw:opacity-65">{{ t("FVTT_SCENE_MERGER.Layout.Help") }}</p>
        </div>
        <div class="tw:flex tw:flex-wrap tw:gap-1">
          <span class="dui-badge dui-badge-outline dui-badge-sm"
            >X {{ Math.round(store.arrangementBounds.minX) }} →
            {{ Math.round(store.arrangementBounds.maxX) }}</span
          >
          <span class="dui-badge dui-badge-outline dui-badge-sm"
            >Y {{ Math.round(store.arrangementBounds.minY) }} →
            {{ Math.round(store.arrangementBounds.maxY) }}</span
          >
          <span class="dui-badge dui-badge-secondary dui-badge-sm"
            >{{ Math.round(store.arrangementBounds.width).toLocaleString() }} ×
            {{ Math.round(store.arrangementBounds.height).toLocaleString() }}</span
          >
        </div>
      </div>

      <LayoutToolbar
        :t="t"
        @fit="workspaceComponent?.fit()"
        @reset="workspaceComponent?.reset()"
        @zoom="workspaceComponent?.zoom($event)"
      />
      <WorkspaceCanvas ref="workspaceComponent" :t="t" />

      <div
        v-if="store.overlaps.length"
        role="alert"
        class="dui-alert dui-alert-warning dui-alert-soft tw:py-2 tw:text-sm"
      >
        <span aria-hidden="true">△</span>
        <span>{{
          t("FVTT_SCENE_MERGER.Layout.OverlapWarning", { count: store.overlaps.length })
        }}</span>
      </div>
    </div>
  </section>
</template>
