import type { FoundrySceneControl } from "../../types/foundry";
import type { ModuleApi } from "../../types/module/api";
import { openSceneMergerApplication } from "../apps/scene-merger/SceneMergerApplication";
import { registerModuleApi } from "../api/register-module-api";
import { I18N_PREFIX, MODULE_ID } from "../constants";
import { registerSettings } from "../settings/register-settings";
import { requireGame } from "../runtime/runtime-utils";

export function registerModuleHooks(): void {
  Hooks.once("init", () => {
    registerSettings();
    registerModuleApi();
  });
  Hooks.once("ready", () => {
    const api = moduleApi();
    Hooks.callAll("fvttSceneMergerRegisterExtensions", api);
    Hooks.callAll("fvttSceneMergerReady", api);
  });
  Hooks.on("getSceneControlButtons", (...args: unknown[]) => {
    registerSceneControl(args[0] as Record<string, FoundrySceneControl>);
  });
}

function registerSceneControl(controls: Record<string, FoundrySceneControl>): void {
  const runtime = requireGame();
  if (!runtime.user.isGM) return;
  const control = controls["tiles"] ?? controls["tokens"];
  if (!control) return;
  control.tools[`${MODULE_ID}-open`] = {
    button: true,
    icon: "fa-solid fa-object-group",
    name: `${MODULE_ID}-open`,
    onChange: () => {
      void openSceneMergerApplication();
    },
    order: Object.keys(control.tools).length,
    title: `${I18N_PREFIX}.Controls.Open`,
    visible: true,
  };
}

function moduleApi(): ModuleApi {
  const api = requireGame().modules.get(MODULE_ID)?.api;
  if (!api) throw new Error("Scene Merger API is unavailable after initialization.");
  return api;
}
