import type {
  MergeProgress,
  MergeRequest,
  MergeSummary,
  SceneMergerServices,
  ValidationReport,
} from "../../types/scene-merger";
import { logger } from "../logging/logger";
import { cleanupPartialDestinations } from "../settings/settings-values";
import { MergeCancellation } from "./merge/errors";
import { foundryMergeRuntime } from "./merge/foundry-runtime";
import { runMergeWorkflow } from "./merge/workflow";
import { listSceneFolders, listSceneSummaries } from "./scene-snapshots";
import { formatIssueCode, requireScene } from "./runtime-utils";
import {
  issueIdentifier,
  unacknowledgedWarnings,
  validateRequest,
  validateRequestWithScenes,
} from "./validation-service";

export interface CancellableSceneMergerService extends SceneMergerServices {
  cancelActiveMerge(): void;
}

let activeCancellation: MergeCancellation | undefined;

async function merge(
  request: MergeRequest,
  onProgress?: (progress: MergeProgress) => void,
): Promise<MergeSummary> {
  if (activeCancellation) {
    throw new Error("Another Scene merge is already in progress on this client.");
  }
  const cancellation = new MergeCancellation();
  activeCancellation = cancellation;
  try {
    onProgress?.({
      completed: 0,
      detail: "Validating source Scenes",
      stage: "validating",
      total: 1,
    });
    const validation = await validateRequestWithScenes(request);
    logger.debug("Scene merge request validated", {
      acknowledgedWarnings: request.acknowledgedWarnings.length,
      blocking: validation.report.blocking.map((issue) => issue.code),
      enabledContent: Object.entries(request.options.content).flatMap(([category, enabled]) =>
        enabled ? [category] : [],
      ),
      placementCount: request.placements.length,
      sourceCount: validation.scenes.length,
      warnings: validation.report.warnings.map((issue) => issue.code),
    });
    if (validation.report.blocking.length > 0) {
      throw new Error(
        `Scene merge is blocked: ${validation.report.blocking
          .map((issue) => formatIssueCode(issue.code))
          .join(", ")}.`,
      );
    }
    const unacknowledged = unacknowledgedWarnings(request, validation.report);
    if (unacknowledged.length > 0) {
      throw new Error(
        `Review and acknowledge ${unacknowledged.length} merge warning(s) before continuing.`,
      );
    }
    onProgress?.({
      completed: 1,
      detail: "Source Scenes validated",
      stage: "validating",
      total: 1,
    });
    cancellation.throwIfCancelled();
    const summary = await runMergeWorkflow(request, validation.scenes, {
      cancellation,
      cleanupPartial: cleanupPartialDestinations(),
      ...(onProgress ? { onProgress } : {}),
      runtime: foundryMergeRuntime,
      validationWarnings: validation.report.warnings.map(issueIdentifier),
    });
    logger.info("Scene merge completed", summary);
    foundryMergeRuntime.notifyInfo(`Created Scene “${summary.destinationSceneName}”.`);
    return summary;
  } catch (error) {
    logger.error("Scene merge failed", error);
    foundryMergeRuntime.notifyError(error instanceof Error ? error.message : String(error));
    throw error;
  } finally {
    activeCancellation = undefined;
  }
}

export const sceneMergerService: CancellableSceneMergerService = {
  cancelActiveMerge(): void {
    activeCancellation?.cancel();
  },
  listSceneFolders,
  listScenes: listSceneSummaries,
  merge,
  async openScene(sceneId: string): Promise<void> {
    await requireScene(sceneId).view();
  },
  validate(request: MergeRequest): Promise<ValidationReport> {
    return validateRequest(request);
  },
};
