import type { FoundryData, FoundryDocument, FoundryScene } from "../../types/foundry";
import type {
  CoreDocumentType,
  SceneBackgroundSummary,
  SceneDocumentCounts,
  SceneFolderSummary,
  SceneMetrics,
  SceneSnapshot,
  SceneSummary,
  SerializedRecord,
} from "../../types/scene-merger";
import { MODULE_ID } from "../constants";
import {
  asRecord,
  asRecords,
  cloneRecord,
  isAnimatedAsset,
  numeric,
  requireGame,
  requireScene,
  serializeDocument,
  text,
} from "./runtime-utils";

export const EMBEDDED_TYPES: readonly CoreDocumentType[] = [
  "Tile",
  "Wall",
  "AmbientLight",
  "AmbientSound",
  "Drawing",
  "Note",
  "Region",
  "Token",
];

const CORE_REGION_SHAPES = new Set([
  "circle",
  "cone",
  "ellipse",
  "emanation",
  "grid",
  "line",
  "polygon",
  "rectangle",
  "ring",
  "token",
]);

export async function listSceneSummaries(): Promise<readonly SceneSummary[]> {
  return requireGame().scenes.contents.map((scene) => snapshotScene(scene, false));
}

export async function listSceneFolders(): Promise<readonly SceneFolderSummary[]> {
  return requireGame()
    .folders.contents.filter((folder) => folder.id && folder.type === "Scene")
    .map((folder) => ({ id: folder.id ?? "", name: folder.name }));
}

export function loadSceneSnapshots(sceneIds: readonly string[]): readonly SceneSnapshot[] {
  return sceneIds.map((sceneId) => snapshotScene(requireScene(sceneId), true) as SceneSnapshot);
}

function snapshotScene(scene: FoundryScene, withDocuments: boolean): SceneSummary | SceneSnapshot {
  const runtime = requireGame();
  const documents = collectDocuments(scene);
  const levels = scene.levels.contents.map((level) => ({
    elevation: {
      bottom: numeric(level.elevation?.bottom),
      top: numeric(level.elevation?.top),
    },
    id: level.id ?? "",
    name: level.name ?? "Level",
  }));
  const summary: SceneSummary = {
    background: readBackground(scene),
    canMerge:
      runtime.user.isGM &&
      Scene.implementation.canUserCreate(runtime.user) &&
      scene.canUserModify(runtime.user, "update"),
    dimensions: {
      height: scene.dimensions.height,
      sceneHeight: scene.dimensions.sceneHeight,
      sceneWidth: scene.dimensions.sceneWidth,
      sceneX: scene.dimensions.sceneX,
      sceneY: scene.dimensions.sceneY,
      width: scene.dimensions.width,
    },
    folderId: scene.folder?.id ?? null,
    folderName: scene.folder?.name ?? null,
    grid: {
      distance: scene.grid.distance,
      size: scene.grid.size,
      type: scene.grid.type,
      units: scene.grid.units,
    },
    id: scene.id ?? "",
    levels,
    metrics: measureScene(scene, documents),
    name: scene.name ?? "Untitled Scene",
    thumbnail: scene.thumbnail,
  };

  if (!withDocuments) return summary;
  return {
    ...summary,
    documents,
    source: serializeDocument(scene),
  };
}

function collectDocuments(
  scene: FoundryScene,
): Readonly<Partial<Record<CoreDocumentType, readonly SerializedRecord[]>>> {
  const documents: Partial<Record<CoreDocumentType, readonly SerializedRecord[]>> = {
    Level: scene.levels.contents.map(serializeDocument),
  };
  for (const type of EMBEDDED_TYPES) {
    documents[type] = scene.getEmbeddedCollection(type).contents.map(serializeDocument);
  }
  return documents;
}

function readBackground(scene: FoundryScene): SceneBackgroundSummary | null {
  const level = scene.levels.contents[0];
  const levelData = level ? serializeDocument(level) : undefined;
  const background = asRecord(levelData?.["background"]);
  const source = background?.["src"];
  const color = background?.["color"];
  const hasSource = typeof source === "string" && source.length > 0;
  const hasColor =
    (typeof color === "string" && color.length > 0) ||
    (typeof color === "number" && Number.isFinite(color));
  if (!hasSource && !hasColor) return null;
  return {
    animated: hasSource && isAnimatedAsset(source),
    color: hasColor ? color : null,
    height: scene.dimensions.sceneHeight,
    rotation: 0,
    scaleX: 1,
    scaleY: 1,
    src: hasSource ? source : null,
    width: scene.dimensions.sceneWidth,
    x: 0,
    y: 0,
  };
}

function measureScene(
  scene: FoundryScene,
  documents: ReturnType<typeof collectDocuments>,
): SceneMetrics {
  const counts: Partial<Record<CoreDocumentType, number>> = {};
  let attachedRegions = 0;
  let animatedAssets = 0;
  let backgroundImages = 0;
  let crossSceneReferences = 0;
  let gridRegionShapes = 0;
  let moduleFlagDocuments = 0;
  let texturePixels = 0;
  let tokenRegionShapes = 0;
  let unsupportedRegionBehaviors = 0;
  let unsupportedRegionShapes = 0;

  moduleFlagDocuments += hasUnsupportedModuleFlags(serializeDocument(scene)) ? 1 : 0;

  for (const level of scene.levels.contents) {
    const levelData = serializeDocument(level);
    for (const layer of [asRecord(levelData["background"]), asRecord(levelData["foreground"])]) {
      if (!layer?.["src"]) continue;
      backgroundImages += 1;
      animatedAssets += isAnimatedAsset(layer["src"]) ? 1 : 0;
      texturePixels += scene.dimensions.sceneWidth * scene.dimensions.sceneHeight;
    }
  }

  for (const [type, values] of Object.entries(documents)) {
    counts[type as CoreDocumentType] = values.length;
    for (const value of values) {
      const metrics = inspectDocument(value, scene.id ?? "");
      animatedAssets += metrics.animated;
      attachedRegions += metrics.attachedRegion;
      crossSceneReferences += metrics.crossReferences;
      gridRegionShapes += metrics.gridShapes;
      moduleFlagDocuments += metrics.moduleFlags;
      texturePixels += metrics.texturePixels;
      tokenRegionShapes += metrics.tokenRegionShapes;
      unsupportedRegionBehaviors += metrics.regionBehaviors;
      unsupportedRegionShapes += metrics.unsupportedRegionShapes;
    }
  }
  counts.RegionBehavior = (documents.Region ?? []).reduce(
    (total, region) => total + asRecords(region["behaviors"]).length,
    0,
  );
  return {
    attachedRegions,
    animatedAssets,
    backgroundImages,
    crossSceneReferences,
    documents: counts as SceneDocumentCounts,
    gridRegionShapes,
    moduleFlagDocuments,
    texturePixels,
    tokenRegionShapes,
    unsupportedRegionBehaviors,
    unsupportedRegionShapes,
  };
}

function inspectDocument(value: SerializedRecord, sceneId: string) {
  const texture = asRecord(value["texture"]);
  const path = texture?.["src"];
  const attachment = asRecord(value["attachment"]);
  const shapes = asRecords(value["shapes"]);
  const behaviors = asRecords(value["behaviors"]);
  return {
    animated: isAnimatedAsset(path) ? 1 : 0,
    attachedRegion:
      typeof attachment?.["token"] === "string" && attachment["token"].length > 0 ? 1 : 0,
    crossReferences: countCrossSceneReferences(value, sceneId),
    gridShapes: shapes.filter((shape) => text(shape["type"]) === "grid").length,
    moduleFlags: hasUnsupportedModuleFlags(value) ? 1 : 0,
    regionBehaviors: behaviors.filter(
      (behavior) =>
        hasLikelyReference(behavior) ||
        text(behavior["type"]).toLowerCase().includes("changelevel"),
    ).length,
    texturePixels: texture ? numeric(value["width"]) * numeric(value["height"]) : 0,
    tokenRegionShapes: shapes.filter((shape) => text(shape["type"]) === "token").length,
    unsupportedRegionShapes: shapes.filter((shape) => !CORE_REGION_SHAPES.has(text(shape["type"])))
      .length,
  };
}

function hasUnsupportedModuleFlags(value: SerializedRecord): boolean {
  const flags = asRecord(value["flags"]);
  return Boolean(
    flags && Object.keys(flags).some((scope) => scope !== "core" && scope !== MODULE_ID),
  );
}

function countCrossSceneReferences(value: unknown, sourceSceneId: string): number {
  if (typeof value === "string") {
    return [...value.matchAll(/Scene\.([A-Za-z0-9_-]+)/g)].filter(
      (match) => match[1] !== sourceSceneId,
    ).length;
  }
  if (Array.isArray(value)) {
    return value.reduce<number>(
      (sum, child) => sum + countCrossSceneReferences(child, sourceSceneId),
      0,
    );
  }
  const record = asRecord(value);
  return record
    ? Object.values(record).reduce<number>(
        (sum, child) => sum + countCrossSceneReferences(child, sourceSceneId),
        0,
      )
    : 0;
}

function hasLikelyReference(value: unknown): boolean {
  if (typeof value === "string") return /(?:Scene|Region|Token)\./.test(value);
  if (Array.isArray(value)) return value.some(hasLikelyReference);
  const record = asRecord(value);
  if (!record) return false;
  return Object.entries(record).some(([key, child]) => {
    if (/^(?:destination|region|scene|token|uuid)/i.test(key)) return true;
    return hasLikelyReference(child);
  });
}

export function cloneSourceDocument(document: FoundryDocument): FoundryData {
  return cloneRecord(document.toObject(true));
}
