<script setup lang="ts">
/* eslint-disable vue/html-closing-bracket-newline -- Prettier owns Vue template formatting. */
import { computed } from "vue";

import type { SceneMergerLocalizer } from "../../../../state/scene-merger";
import { useSceneMergerStore } from "../../../../state/scene-merger";
import type { CoreDocumentType } from "../../../../types/scene-merger";

const props = defineProps<{ readonly t: SceneMergerLocalizer }>();
const store = useSceneMergerStore();

const progressPercent = computed(() => {
  const progress = store.progress;
  return progress && progress.total > 0
    ? Math.round((progress.completed / progress.total) * 100)
    : 0;
});

const copied = computed(() => summaryEntries(store.summary?.copied));
const skipped = computed(() => summaryEntries(store.summary?.skipped));

function summaryEntries(counts: Readonly<Partial<Record<CoreDocumentType, number>>> | undefined) {
  return Object.entries(counts ?? {})
    .filter(
      (entry): entry is [CoreDocumentType, number] => typeof entry[1] === "number" && entry[1] > 0,
    )
    .sort(([first], [second]) => first.localeCompare(second));
}

function localizeSummaryWarning(warning: string): string {
  const separator = warning.indexOf(":");
  const code = separator < 0 ? warning : warning.slice(0, separator);
  const suffix = separator < 0 ? "" : warning.slice(separator + 1);
  const key = `FVTT_SCENE_MERGER.Validation.Issues.${code.replace(".", "_")}`;
  const localized = props.t(key);
  if (localized === key) return warning;
  return suffix ? `${localized} — ${suffix}` : localized;
}
</script>

<template>
  <footer class="dui-card dui-card-border tw:bg-base-200">
    <div
      v-if="store.status === 'ready'"
      class="dui-card-body tw:flex-row tw:flex-wrap tw:items-center tw:justify-between tw:gap-3 tw:p-3"
    >
      <div>
        <h2 class="dui-card-title tw:text-base">{{ t("FVTT_SCENE_MERGER.Execution.Title") }}</h2>
        <p class="tw:m-0 tw:text-xs tw:opacity-65">
          {{
            t("FVTT_SCENE_MERGER.Execution.ReadySummary", {
              count: store.selectedScenes.length,
              width: Math.round(store.arrangementBounds.width),
              height: Math.round(store.arrangementBounds.height),
            })
          }}
        </p>
      </div>
      <div class="tw:flex tw:items-center tw:gap-2">
        <span v-if="!store.canMerge" class="tw:max-w-72 tw:text-right tw:text-xs tw:opacity-65">{{
          t("FVTT_SCENE_MERGER.Execution.ResolveIssues")
        }}</span>
        <button
          class="dui-btn dui-btn-primary"
          type="button"
          :disabled="!store.canMerge"
          @click="store.merge()"
        >
          {{ t("FVTT_SCENE_MERGER.Actions.Merge") }}
        </button>
      </div>
    </div>

    <div v-else-if="store.status === 'merging'" class="dui-card-body tw:gap-3 tw:p-3">
      <div class="tw:flex tw:flex-wrap tw:items-center tw:justify-between tw:gap-2">
        <div>
          <h2 class="dui-card-title tw:text-base">
            {{ t("FVTT_SCENE_MERGER.Execution.Merging") }}
          </h2>
          <p class="tw:m-0 tw:text-xs tw:opacity-70">
            {{
              store.progress
                ? t(`FVTT_SCENE_MERGER.MergeStage.${store.progress.stage}`)
                : t("FVTT_SCENE_MERGER.MergeStage.validating")
            }}
            <span v-if="store.progress?.detail"> · {{ store.progress.detail }}</span>
          </p>
        </div>
        <button
          v-if="store.canCancel"
          class="dui-btn dui-btn-warning dui-btn-outline dui-btn-sm"
          type="button"
          @click="store.cancelMerge()"
        >
          {{
            store.cancelRequested
              ? t("FVTT_SCENE_MERGER.Actions.Cancelling")
              : t("FVTT_SCENE_MERGER.Actions.Cancel")
          }}
        </button>
        <span v-else class="dui-badge dui-badge-ghost dui-badge-sm">{{
          t("FVTT_SCENE_MERGER.Execution.CancellationClosed")
        }}</span>
      </div>
      <progress class="dui-progress tw:w-full" :value="progressPercent" max="100" />
      <div class="tw:flex tw:justify-between tw:text-[0.68rem] tw:opacity-65">
        <span>{{ t("FVTT_SCENE_MERGER.Execution.SourceSafety") }}</span>
        <span>{{ progressPercent }}%</span>
      </div>
    </div>

    <div
      v-else-if="store.status === 'success' && store.summary"
      class="dui-card-body tw:gap-3 tw:p-3"
    >
      <div role="alert" class="dui-alert dui-alert-success dui-alert-soft">
        <span aria-hidden="true">✓</span>
        <div class="tw:min-w-0 tw:flex-1">
          <h2 class="tw:m-0 tw:font-semibold">
            {{
              t("FVTT_SCENE_MERGER.Results.SuccessTitle", {
                name: store.summary.destinationSceneName,
              })
            }}
          </h2>
          <p class="tw:m-0 tw:text-sm">
            {{
              t("FVTT_SCENE_MERGER.Results.SuccessDimensions", {
                width: store.summary.destinationWidth,
                height: store.summary.destinationHeight,
                count: store.summary.sourceCount,
              })
            }}
          </p>
        </div>
        <button class="dui-btn dui-btn-sm" type="button" @click="store.openDestination()">
          {{ t("FVTT_SCENE_MERGER.Actions.OpenScene") }}
        </button>
      </div>

      <div class="tw:grid tw:gap-3 tw:md:grid-cols-2 tw:xl:grid-cols-4">
        <section class="tw:rounded-box tw:bg-base-300/50 tw:p-3">
          <h3 class="tw:mt-0 tw:mb-2 tw:text-sm tw:font-semibold">
            {{ t("FVTT_SCENE_MERGER.Results.Copied") }}
          </h3>
          <ul class="tw:m-0 tw:grid tw:list-none tw:gap-1 tw:p-0 tw:text-xs">
            <li
              v-for="[type, count] in copied"
              :key="type"
              class="tw:flex tw:justify-between tw:gap-2"
            >
              <span>{{ t(`FVTT_SCENE_MERGER.Documents.${type}`) }}</span
              ><strong>{{ count }}</strong>
            </li>
            <li v-if="copied.length === 0" class="tw:opacity-60">
              {{ t("FVTT_SCENE_MERGER.Results.None") }}
            </li>
          </ul>
        </section>
        <section class="tw:rounded-box tw:bg-base-300/50 tw:p-3">
          <h3 class="tw:mt-0 tw:mb-2 tw:text-sm tw:font-semibold">
            {{ t("FVTT_SCENE_MERGER.Results.Skipped") }}
          </h3>
          <ul class="tw:m-0 tw:grid tw:list-none tw:gap-1 tw:p-0 tw:text-xs">
            <li
              v-for="[type, count] in skipped"
              :key="type"
              class="tw:flex tw:justify-between tw:gap-2"
            >
              <span>{{ t(`FVTT_SCENE_MERGER.Documents.${type}`) }}</span
              ><strong>{{ count }}</strong>
            </li>
            <li v-if="skipped.length === 0" class="tw:opacity-60">
              {{ t("FVTT_SCENE_MERGER.Results.NoneSkipped") }}
            </li>
          </ul>
        </section>
        <section class="tw:rounded-box tw:bg-base-300/50 tw:p-3">
          <h3 class="tw:mt-0 tw:mb-2 tw:text-sm tw:font-semibold">
            {{ t("FVTT_SCENE_MERGER.Results.Diagnostics") }}
          </h3>
          <dl class="tw:m-0 tw:grid tw:grid-cols-[1fr_auto] tw:gap-x-3 tw:gap-y-1 tw:text-xs">
            <dt>{{ t("FVTT_SCENE_MERGER.Results.Rewritten") }}</dt>
            <dd class="tw:m-0 tw:font-semibold">{{ store.summary.referencesRewritten }}</dd>
            <dt>{{ t("FVTT_SCENE_MERGER.Results.Unresolved") }}</dt>
            <dd class="tw:m-0 tw:font-semibold">{{ store.summary.unresolvedReferences.length }}</dd>
            <dt>{{ t("FVTT_SCENE_MERGER.Results.Warnings") }}</dt>
            <dd class="tw:m-0 tw:font-semibold">{{ store.summary.warnings.length }}</dd>
          </dl>
        </section>
        <section class="tw:rounded-box tw:bg-base-300/50 tw:p-3">
          <h3 class="tw:mt-0 tw:mb-2 tw:text-sm tw:font-semibold">
            {{ t("FVTT_SCENE_MERGER.Results.Review") }}
          </h3>
          <ul class="tw:m-0 tw:max-h-24 tw:overflow-auto tw:pl-4 tw:text-xs">
            <li v-for="warning in store.summary.warnings" :key="warning">
              {{ localizeSummaryWarning(warning) }}
            </li>
            <li v-for="reference in store.summary.unresolvedReferences" :key="reference">
              {{ reference }}
            </li>
            <li
              v-if="!store.summary.warnings.length && !store.summary.unresolvedReferences.length"
              class="tw:list-none tw:opacity-60"
            >
              {{ t("FVTT_SCENE_MERGER.Results.NoReviewItems") }}
            </li>
          </ul>
        </section>
      </div>
      <div class="dui-card-actions tw:justify-end">
        <button
          class="dui-btn dui-btn-ghost dui-btn-sm"
          type="button"
          @click="store.returnToEditing()"
        >
          {{ t("FVTT_SCENE_MERGER.Actions.MergeAnother") }}
        </button>
      </div>
    </div>

    <div v-else-if="store.status === 'failure'" class="dui-card-body tw:gap-3 tw:p-3">
      <div role="alert" class="dui-alert dui-alert-error dui-alert-soft">
        <span aria-hidden="true">×</span>
        <div class="tw:min-w-0 tw:flex-1">
          <h2 class="tw:m-0 tw:font-semibold">{{ t("FVTT_SCENE_MERGER.Results.FailureTitle") }}</h2>
          <p class="tw:m-0 tw:text-sm">
            {{
              t("FVTT_SCENE_MERGER.Results.FailureStage", {
                stage: t(`FVTT_SCENE_MERGER.MergeStage.${store.failureStage}`),
              })
            }}
          </p>
          <code class="tw:mt-1 tw:block tw:break-words tw:text-xs">{{ store.failureMessage }}</code>
          <p class="tw:mt-2 tw:mb-0 tw:text-xs">
            {{ t("FVTT_SCENE_MERGER.Results.FailureSafety") }}
          </p>
        </div>
        <button class="dui-btn dui-btn-sm" type="button" @click="store.returnToEditing()">
          {{ t("FVTT_SCENE_MERGER.Actions.BackToSetup") }}
        </button>
      </div>
    </div>
  </footer>
</template>
