import { computed, type Ref } from "vue";

import { calculateArrangementBounds, findPlacementOverlaps } from "../../functions/scene-merger";
import type {
  ContentSelection,
  DestinationOptions,
  MergeOptions,
  MergeRequest,
  SceneFolderSummary,
  ScenePlacement,
  SceneSummary,
  ValidationReport,
} from "../../types/scene-merger";

interface DerivationSources {
  readonly availableScenes: Ref<readonly SceneSummary[]>;
  readonly content: ContentSelection;
  readonly destination: DestinationOptions;
  readonly placements: Ref<readonly ScenePlacement[]>;
  readonly sceneFolders: Ref<readonly SceneFolderSummary[]>;
  readonly validation: Ref<ValidationReport | null>;
  readonly warningsAcknowledged: Ref<boolean>;
}

export function createWorkflowDerivations(sources: DerivationSources) {
  const selectedScenes = computed(() => {
    const byId = new Map(sources.availableScenes.value.map((scene) => [scene.id, scene]));
    return sources.placements.value.flatMap((placement) => {
      const scene = byId.get(placement.sceneId);
      return scene ? [scene] : [];
    });
  });
  const selectedSceneIds = computed(() => sources.placements.value.map(({ sceneId }) => sceneId));
  const arrangementBounds = computed(() => calculateArrangementBounds(sources.placements.value));
  const overlaps = computed(() => findPlacementOverlaps(sources.placements.value));
  const folderChoices = computed(() =>
    [...sources.sceneFolders.value].sort((a, b) => a.name.localeCompare(b.name)),
  );
  const options = computed<MergeOptions>(() => ({
    content: { ...sources.content },
    destination: { ...sources.destination },
  }));
  const currentRequest = computed<MergeRequest>(() => ({
    acknowledgedWarnings: sources.warningsAcknowledged.value
      ? [...new Set(sources.validation.value?.warnings.map(({ code }) => code) ?? [])]
      : [],
    options: options.value,
    placements: sources.placements.value,
    sourceSceneIds: selectedSceneIds.value,
  }));

  return {
    arrangementBounds,
    currentRequest,
    folderChoices,
    overlaps,
    selectedSceneIds,
    selectedScenes,
  };
}
