import type {
  CoreDocumentType,
  DocumentTransformContext,
  MergeRequest,
  MergeSummary,
  ReferenceRewriteContext,
  ReferenceRewriteResult,
  SceneMergerExtension,
  SceneSnapshot,
  SerializedRecord,
  ValidationIssue,
} from "../../types/scene-merger";

export type ExtensionDisposer = () => void;

const extensions = new Map<string, SceneMergerExtension>();

export function registerExtension(extension: SceneMergerExtension): ExtensionDisposer {
  if (!extension.id.trim()) {
    throw new Error("A Scene Merger extension must have a non-empty id.");
  }
  if (extensions.has(extension.id)) {
    throw new Error(`A Scene Merger extension with id ${extension.id} is already registered.`);
  }
  extensions.set(extension.id, extension);
  return () => extensions.delete(extension.id);
}

export function registeredExtensions(): readonly SceneMergerExtension[] {
  return [...extensions.values()];
}

export function registerDocumentTransformer(
  id: string,
  documentType: CoreDocumentType,
  transformer: (data: SerializedRecord, context: DocumentTransformContext) => SerializedRecord,
): ExtensionDisposer {
  return registerExtension({ documentTransformers: { [documentType]: transformer }, id });
}

export function registerValidator(
  id: string,
  validate: (scenes: readonly SceneSnapshot[], request: MergeRequest) => readonly ValidationIssue[],
): ExtensionDisposer {
  return registerExtension({ id, validate });
}

export function registerReferenceRewriter(
  id: string,
  rewriter: (data: SerializedRecord, context: ReferenceRewriteContext) => ReferenceRewriteResult,
): ExtensionDisposer {
  return registerExtension({ id, referenceRewriter: rewriter });
}

export async function runPreMergeExtensions(request: MergeRequest): Promise<void> {
  for (const extension of registeredExtensions()) {
    await extension.preMerge?.(request);
  }
}

export async function runPostMergeExtensions(summary: MergeSummary): Promise<void> {
  for (const extension of registeredExtensions()) {
    await extension.postMerge?.(summary);
  }
}
